        // Tool calls section: <|tool_calls_section_begin|> tool_calls <|tool_calls_section_end|>
        auto min_calls  = inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_REQUIRED ? 1 : 0;
        auto max_calls  = inputs.parallel_tool_calls ? -1 : 1;
        auto tool_calls = p.rule("tool-calls",
            p.optional(p.literal(SECTION_BEGIN)) +
            p.trigger_rule("tool-call", p.repeat(CALL_BEGIN + tool_choice, min_calls, max_calls) +
                p.optional(p.literal(SECTION_END)))
        );

        auto content_before_tools = p.content(p.until_one_of({ SECTION_BEGIN, CALL_BEGIN }));

        return generation_prompt + reasoning + content_before_tools + tool_calls + end;
    });

    data.parser = parser.save();

    if (include_grammar) {
        data.grammar_lazy = inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_AUTO;
        // ... grammar building
        data.grammar_triggers = {
            { COMMON_GRAMMAR_TRIGGER_TYPE_WORD, "<|tool_call_begin|>" }
        };
    }

    return data;
}
```

---

### **6. Integration Point: Flow from `common_chat_templates_apply_jinja()`**

**File location:** Lines 1693-1784

This shows where specialized templates are invoked:

```cpp
    // ... parameter setup (lines 1695-1753) ...

    if (auto result = common_chat_try_specialized_template(tmpl, src, params)) {
        result->generation_prompt = params.generation_prompt;
        return *result;
    }

    try {
        LOG_DBG("%s: using differential autoparser\n", __func__);
        struct autoparser::autoparser autoparser;
        autoparser.analyze_template(tmpl);
        auto auto_params = autoparser::peg_generator::generate_parser(tmpl, params, autoparser);
        // ... fallback to autoparser ...
    }
```

The flow is:
1. Convert messages to JSON format (line 1701)
2. Calculate generation prompt by comparing renders with/without it (lines 1735-1739)
3. **Try specialized template first** (line 1781)
4. If no specialized handler matches, fall back to differential autoparser

---

### **Summary Table: Handler Patterns**

| Handler | Detection Markers | Thinking Tags | Tool Markers | Key Feature |
|---------|---|---|---|---|
| **Ministral 3** | `[SYSTEM_PROMPT]` + `[TOOL_CALLS]` + `[ARGS]` (NOT `[CALL_ID]`) | `[THINK]` / `[/THINK]` | `[TOOL_CALLS]` + `[ARGS]` | Message restructuring into blocks |
| **GPT-OSS** | `<\|channel\|>` | `<\|channel\|>` sections | `to=functions.NAME` format | Channel-based routing |
| **Functionary** | `>>>all` + `>>>${recipient}` | None | `>>>function_name` | Recipient-based routing |
| **Kimi K2** | `<\|tool_calls_section_begin\|>` + `<\|tool_call_begin\|>` | `<think>` / `</think>` | `functions.NAME:index` format | Indexed tool calls |
| **LFM2** | `<\|tool_list_start\|>` + `<\|tool_list_end\|>` | `<think>` / `</think>` | `<\|tool_call_start\|>` wrappers | Python-style tool syntax |
| **GigaChatV3** | `<\|role_sep\|>` + `<\|message_sep\|>` (NOT `<\|function_call\|>`) | None | JSON object format | Role/message separator based |

All files referenced are absolute paths from the provided working directory.

